//  metropolis.h  –  Metropolis acceptance criterion (LUT-based)
//
//  LUT design
//  ──────────────────────────────────────────────────────────────
//  Index i covers beta*dE in [i/32, (i+1)/32)
//  i.e. resolution = 1/32, range = [0, 8.0)
//
//  threshold[i] = round( exp(-i/32) * 0xFFFF_FFFF )
//
//  Acceptance: flip spin if rand32 < threshold[lut_idx]
//    (where rand32 is a uniform 32-bit random number)
//
//  If beta*dE >= 8.0 (lut_idx >= 256), threshold = 0 → always reject
//
//  Generated by:
//    python3 -c "import math; \
//      print([round(math.exp(-i/32)*0xFFFFFFFF) for i in range(256)])"
// ============================================================

