// ── Metropolis acceptance function ─────────────────────────────
//
//  beta_dE : beta * delta_E  (must be >= 0; caller ensures this)
//            represented as ap_ufixed<24,12>
//  rand32  : uniform 32-bit random number
//  returns : true → accept the spin flip
//
// Note: for dE <= 0 always accept (caller handles this branch).
inline bool metropolis_accept(ap_ufixed<24, 12> beta_dE, ap_uint<32> rand32)
{
#pragma HLS INLINE
    // LUT index = floor(beta_dE * 32)
    // beta_dE has 12 fractional bits; *32 = shift left 5
    // We need the 8-bit integer part of (beta_dE * 32).
    // beta_dE * 32 is ap_ufixed<24,17>; take upper 9 bits of integer part.
    ap_ufixed<24, 17> scaled = beta_dE * ap_ufixed<6, 6>(32);
    ap_uint<9> idx = (ap_uint<9>)(ap_uint<17>)scaled;   // integer part, 9-bit wide

    if (idx >= 256) return false;   // exp(-8+) ≈ 0, reject

    uint32_t threshold = METROPOLIS_LUT[(uint8_t)idx];
    return (uint32_t)rand32 < threshold;
}
